SELECT instance_name
  FROM ui_instances
  WHERE is_active = 1;

SELECT element_name
FROM ui_elements
WHERE is_deprecated = 0;

SELECT COUNT(*) AS overridden_property_count
FROM instance_properties
WHERE instance_id = 1 AND is_override = 1;

SELECT option_name
FROM alignment_options
WHERE is_default = 1;

SELECT font_name
FROM font_styles
WHERE is_default = 1;

SELECT COUNT(*) AS active_instances
FROM ui_instances
WHERE is_active = 1;

SELECT value
FROM instance_properties
WHERE is_override = 1;

SELECT COUNT(*) AS non_deprecated_elements
  FROM ui_elements
  WHERE is_deprecated = 0;
